#include <stdio.h>
#include <stdlib.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long total, per;
        if (scanf("%lld %lld", &total, &per) != 2) break;
        long long rows = total / per;
        long long left = total % per;
        printf("%lld\n%lld\n", rows, left);
    }
    return 0;
}

